};

const styles = {
    Dashboard: { width: "1160px", position:"relative", margin:"0 auto", padding: "0 22px",paddingTop: "24px",
        paddingBottom:"60px", height: "100vh", overflow: "hidden", backgroundColor: "hsl(52, 3%, 86%)",
        boxShadow: "0 0 2px rgba(0,0,0,0.22)" },
    container: {},
    flexRow: { display: "flex", gap: "20px", height: "calc(100% - 20px)" },
    column:{display: "block"},
    col_title:{ textTransform: "uppercase",
        fontWeight: 700,
        fontSize: "10px",
        color: "#666",
