        transition: "transform 0.3s ease, box-shadow 0.3s ease, backgroundColor 0.3s ease",
        boxShadow: "0 2px 6px rgba(0,0,0,0.1)", },
    News: { border: "1px solid #ccc",
        color: "#fff",
        padding: "10px",
        marginBottom: "10px",
        borderRadius: "4px",
        cursor: "pointer",
        height: "40px",
        display: "flex",
        alignItems: "center",
        backgroundColor: "#1b365d",
        transition: "transform 0.3s ease, box-shadow 0.3s ease, backgroundColor 0.3s ease",
        boxShadow: "0 2px 6px rgba(0,0,0,0.1)",},
    Clubs: { border: "1px solid #ccc",
        color: "#fff",
        padding: "12px 12px",
        marginBottom: "10px",
        borderRadius: "4px",
        cursor: "pointer",
        height: "40px",
        display: "flex",
        alignItems: "center",
        backgroundColor: "#1b365d",
